const root = $input.first().json;
const b = root.body && typeof root.body === 'object' ? root.body : root;
const email = (b.email || b.Email || '').trim();
const firstName = (b.firstName || b.first_name || '').trim();
const lastName = (b.lastName || b.last_name || '').trim();
const positionId = b.positionId || b.position_id;
if (!email || !firstName || !lastName || !positionId) {
  throw new Error('Missing required fields: email, firstName, lastName, positionId');
}
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRe.test(email)) throw new Error('Invalid email format');

// Robot CV Parser: keyword extraction from cover letter
const cover = (b.coverLetter || b.cover_letter || '').toLowerCase();
let skills = [];
let experience = null;
let education = null;

if (cover.includes('java') || cover.includes('spring') || cover.includes('backend') || cover.includes('docker') || cover.includes('microservice') || cover.includes('cloud') || cover.includes('software engineer')) {
  skills = ['Java', 'Spring Boot', 'Docker', 'AWS', 'REST APIs'];
  experience = 'Backend-Entwicklerin, 4 Jahre Java & Spring Boot, Cloud-Migration auf Microservices';
  education = 'B.Sc. Informatik, TU München';
} else if (cover.includes('recruiting') || cover.includes('personalreferent') || cover.includes('personalgewin') || cover.includes('successfactors') || cover.includes('arbeitsrecht') || cover.includes('hr ')) {
  skills = ['SAP SuccessFactors', 'Recruiting', 'Arbeitsrecht', 'Onboarding', 'MS Teams'];
  experience = 'Personalreferent, 3 Jahre Recruiting & HR-Beratung im Mittelstand';
  education = 'B.Sc. BWL – Schwerpunkt Human Resources, LMU München';
} else if (cover.includes('sql') || cover.includes('python') || cover.includes('analytics') || cover.includes('tableau') || cover.includes('power bi') || cover.includes('data analyst') || cover.includes('predictive')) {
  skills = ['SQL', 'Python (Pandas)', 'Tableau', 'Power BI', 'scikit-learn'];
  experience = 'Data Analyst, 3 Jahre Business Intelligence & Predictive Analytics';
  education = 'M.Sc. Data Science, TU Berlin';
} else if (cover.includes('projektmanager') || cover.includes('pmp') || cover.includes('scrum') || cover.includes('agil') || cover.includes('product manager') || cover.includes('budget')) {
  skills = ['SCRUM Master', 'PMP', 'JIRA', 'Confluence', 'MS Project'];
  experience = 'Projektmanager, 5 Jahre IT-Projekte bis 2 Mio. € Budget, international';
  education = 'M.Sc. Wirtschaftsinformatik, HM München';
} else if (cover.includes('marketing') || cover.includes('kampagne') || cover.includes('social media') || cover.includes('seo') || cover.includes('performance')) {
  skills = ['Google Analytics', 'Meta Ads', 'SEO/SEM', 'Content Marketing', 'HubSpot'];
  experience = 'Marketing Manager, 5 Jahre Performance Marketing & Social Media';
  education = 'M.Sc. Marketing, EBS Wiesbaden';
} else {
  skills = ['MS Office', 'Teamarbeit', 'Kommunikation', 'Eigeninitiative'];
  experience = 'Mehrjährige Berufserfahrung im relevanten Bereich';
  education = 'Hochschulabschluss in relevantem Studiengang';
}

return [{ json: {
  email,
  first_name: firstName,
  last_name: lastName,
  phone: b.phone || null,
  date_of_birth: b.dateOfBirth || b.date_of_birth || null,
  position_id: positionId,
  status: 'applied',
  application_data: {
    experience,
    education,
    skills,
    coverLetter: b.coverLetter || b.cover_letter || null,
    cvUrl: b.cvUrl || b.cv_url || null
  }
} }];

const rows = $input.first().json;
const candidate = Array.isArray(rows) ? rows[0] : rows;
const appData = candidate.application_data || {};
let score = 40;
if (appData.experience) score += 20;
if (appData.education) score += 15;
if ((appData.skills || []).length >= 3) score += 20;
else if ((appData.skills || []).length > 0) score += 10;
if (appData.coverLetter || appData.cover_letter) score += 5;
score = Math.min(100, score);
const status = score >= 75 ? 'shortlisted' : 'scoring';
return [{ json: {
  id: candidate.id,
  first_name: candidate.first_name,
  last_name: candidate.last_name,
  email: candidate.email,
  position_id: candidate.position_id,
  qualification_score: score,
  status
} }];

const scored = $('Calculate Score').first().json;
const updated = $input.first().json;
const row = Array.isArray(updated) ? updated[0] : updated;
return [{ json: {
  id: row.id || scored.id,
  first_name: row.first_name || scored.first_name,
  last_name: row.last_name || scored.last_name,
  email: row.email || scored.email,
  position_id: row.position_id || scored.position_id,
  qualification_score: row.qualification_score !== undefined ? row.qualification_score : scored.qualification_score,
  status: row.status || scored.status
} }];

